                <div className="max-w-6xl">
                  <div className="flex flex-wrap items-center gap-4 mb-8">
                      <span className="bg-kph-red text-white px-5 py-2 text-[10px] font-black uppercase rounded-xl shadow-[0_10px_30px_rgba(139,0,0,0.4)] tracking-widest border border-red-400/20">{article.category}</span>
                      <div className="flex items-center gap-2 text-white/80 text-[10px] font-black uppercase tracking-widest bg-black/40 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10">
                        <Clock size={14} className="text-kph-red" /> {article.readTime}
                      </div>
                  </div>
                  <h1 className="text-4xl lg:text-7xl font-black text-white mb-10 max-w-5xl leading-[1.1] font-serif drop-shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
                    {article.title}
                  </h1>
                </div>
            </div>
        </div>

        <div className="container mx-auto px-4 lg:px-8 relative -mt-16 lg:-mt-24 z-10">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 xl:gap-20">
                <div className="lg:col-span-8">
                    <div className="bg-white rounded-[3rem] p-8 lg:p-16 shadow-[0_40px_100px_rgba(0,0,0,0.03)] border border-gray-100">

                        {/* Article Header Metadata */}
                        <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 pb-12 mb-12 border-b border-gray-50">
                           <div className="flex items-center gap-5">
                              <div className="w-16 h-16 rounded-[1.5rem] bg-gray-900 flex items-center justify-center font-black text-white text-xl shadow-2xl">
                                 {article.author.charAt(0)}
                              </div>
                              <div>
                                 <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Written By</p>
                                 <h4 className="text-lg font-black text-kph-charcoal leading-none">{article.author}</h4>
                                 <div className="flex items-center gap-3 mt-2 text-[10px] font-bold text-gray-400">
                                    <span className="flex items-center gap-1"><Calendar size={12} className="text-kph-red" /> {article.date}</span>
                                    <span>•</span>
                                    <span>KPH Verified Journalist</span>
                                 </div>
                              </div>
                           </div>

                           {/* Social Share Desktop */}
                           <div className="flex items-center gap-3">
                              {[
                                { icon: Twitter, color: 'hover:text-sky-500' },
                                { icon: Facebook, color: 'hover:text-blue-600' },
                                { icon: Linkedin, color: 'hover:text-blue-700' },
                                { icon: LinkIcon, color: 'hover:text-kph-red', onClick: handleShare }
                              ].map((social, i) => (
                                <button 
                                  key={i} 
                                  onClick={social.onClick}
                                  className={`w-12 h-12 rounded-2xl bg-gray-50 flex items-center justify-center text-gray-400 transition-all hover:bg-white hover:shadow-xl border border-transparent hover:border-gray-100 ${social.color}`}
                                >
                                   <social.icon size={18} />
                                </button>
                              ))}
                           </div>
                        </div>

                        {/* Article Content */}
                        <article className="prose prose-lg lg:prose-xl max-w-none text-gray-800 leading-[1.8] font-serif selection:bg-kph-red selection:text-white">
                            <p className="lead text-2xl lg:text-3xl font-black mb-12 text-kph-charcoal font-sans tracking-tight leading-snug border-l-8 border-kph-red pl-10 py-4 bg-gray-50 rounded-[2rem]">
                              {article.excerpt}
                            </p>

                            <div className="space-y-8 first-letter:text-7xl first-letter:font-black first-letter:mr-3 first-letter:float-left first-letter:text-kph-red">
                                 {article.content ? (
                                    <div 
                                      className="content-render article-body" 
                                      dangerouslySetInnerHTML={{ __html: article.content.replace(/\n/g, '<br/><br/>') }} 
                                    />
                                 ) : (
                                    <div className="py-20 text-center bg-gray-50 rounded-3xl border-2 border-dashed border-gray-100">
                                       <Loader2 size={32} className="animate-spin mx-auto text-gray-200 mb-4" />
                                       <p className="text-gray-400 font-bold uppercase tracking-widest text-[10px]">Assembling full report...</p>
                                    </div>
                                 )}
                            </div>
                        </article>

                        {/* Article Footer Stats */}
                        <div className="mt-20 pt-12 border-t border-gray-100 flex flex-wrap items-center justify-between gap-6">
                           <div className="flex items-center gap-8">
                              <button 
                                onClick={toggleLike}
                                className={`flex items-center gap-3 px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest transition-all ${
                                  isLiked 
                                    ? 'bg-kph-red text-white shadow-[0_15px_40px_rgba(139,0,0,0.3)]' 
                                    : 'bg-gray-50 text-gray-500 hover:bg-gray-100'
                                }`}
                              >
                                 <ThumbsUp size={16} fill={isLiked ? 'white' : 'none'} /> {likes} Citizens Recommend
                              </button>
                              <div className="flex items-center gap-2 text-gray-400">
                                 {/* Fixed: Added Eye icon here, ensuring it is imported above */}
                                 <Eye size={16} />
                                 <span className="text-[10px] font-black uppercase tracking-widest">4.2k Views</span>
                              </div>
                           </div>
                           <button className="flex items-center gap-2 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-kph-red transition-colors">
                              <ShieldAlert size={16} /> Report Error
                           </button>
                        </div>

                        {/* Comments Section */}
                        <div className="mt-32">
                            <div className="flex items-center justify-between mb-12">
                               <h3 className="text-3xl font-black text-kph-charcoal uppercase tracking-tighter">Community Discourse</h3>
                               <div className="bg-gray-100 px-4 py-1 rounded-full text-[10px] font-black text-gray-500">{comments.length} Comments</div>
                            </div>

                            <form onSubmit={handleSubmit_comment} className="mb-20 relative group">
                                <textarea 
                                    value={commentText}
                                    onChange={(e) => setCommentText(e.target.value)}
                                    maxLength={MAX_CHARS}
                                    placeholder="Add to the conversation... What is your take on this?" 
                                    className="w-full bg-gray-50 border-2 border-gray-100 rounded-[2.5rem] p-10 min-h-[220px] focus:border-kph-red/30 focus:bg-white focus:shadow-2xl focus:shadow-red-900/5 outline-none transition-all font-sans text-lg text-gray-700 resize-none"
                                />
                                <div className="absolute bottom-8 right-8 flex items-center gap-6">
                                  <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">{commentText.length} / {MAX_CHARS}</span>
                                  <button 
                                    type="submit" 
                                    disabled={!commentText.trim()}
                                    className="bg-gray-900 text-white px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-kph-red transition-all shadow-xl disabled:opacity-30 disabled:cursor-not-allowed group-hover:scale-105 active:scale-95"
                                  >
                                    Post Insight
                                  </button>
                                </div>
                            </form>

                            <div className="space-y-12">
                                {comments.length === 0 ? (
                                  <div className="text-center py-24 bg-gray-50 rounded-[3rem] border-4 border-dashed border-gray-100">
                                    <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
                                      <MessageSquare className="text-gray-200" size={32} />
                                    </div>
                                    <p className="text-gray-400 font-black uppercase tracking-[0.2em] text-xs">Be the first to share your perspective</p>
                                  </div>
                                ) : (
                                    comments.map(comment => (
                                        <div key={comment.id} className="flex gap-8 animate-slide-up">
                                            <div className="w-16 h-16 rounded-2xl bg-gray-950 text-white flex items-center justify-center font-black text-xl shadow-2xl shrink-0 group hover:bg-kph-red transition-colors duration-500">
                                              {comment.avatar}
                                            </div>
                                            <div className="flex-1">
                                                <div className="bg-white border border-gray-100 p-10 rounded-[2.5rem] shadow-sm hover:shadow-xl transition-all group">
                                                    <div className="flex justify-between items-center mb-6">
                                                      <div>
                                                        <p className="font-black text-base text-gray-900 tracking-tight leading-none mb-1">{comment.author}</p>
                                                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{comment.time} • Verified Reader</p>
                                                      </div>
                                                      <button className="text-gray-300 hover:text-kph-red transition-colors">
                                                        <MoreHorizontal size={20} />
                                                      </button>
                                                    </div>
                                                    <p className="text-gray-700 leading-relaxed text-lg mb-8">{comment.text}</p>
                                                    <div className="flex items-center gap-6">
                                                       <button className="flex items-center gap-2 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-kph-red transition-colors">
                                                          <ThumbsUp size={14} /> Like
                                                       </button>
                                                       <button className="flex items-center gap-2 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-gray-900 transition-colors">
                                                          Reply
                                                       </button>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Floating Action Bar Mobile Only */}
                <div className="lg:hidden fixed bottom-8 left-8 right-8 z-[60] flex items-center justify-center gap-4">
                  <button 
                    onClick={toggleLike} 
                    className={`flex-1 py-5 rounded-[2rem] font-black text-[10px] uppercase tracking-widest shadow-2xl transition-all flex items-center justify-center gap-3 backdrop-blur-xl border border-white/20 ${
                      isLiked ? 'bg-kph-red text-white' : 'bg-white/95 text-kph-charcoal'
                    }`}
                  >
                    <ThumbsUp size={18} fill={isLiked ? 'white' : 'none'} /> {likes} 
                  </button>
                  <button 
                    onClick={handleShare} 
                    className="flex-1 py-5 bg-gray-900 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 backdrop-blur-xl border border-white/10"
                  >
                    <Share2 size={18} /> Share
                  </button>
                </div>

                {/* Sidebar */}
                <div className="lg:col-span-4 space-y-12">
                   <div className="bg-white rounded-[3rem] p-10 shadow-sm border border-gray-100 hidden lg:block">
                      <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter mb-8 flex items-center gap-3">
                        <Sparkles size={20} className="text-kph-red" /> Deep Dive Analysis
                      </h3>
                      <p className="text-gray-500 text-sm leading-relaxed mb-8">
                        Our political intelligence engine is currently processing the historical data related to this story to provide you with exclusive context.
                      </p>
                      <button className="w-full py-4 bg-gray-50 text-gray-400 font-black text-[10px] uppercase tracking-widest rounded-2xl cursor-not-allowed border border-gray-100">
                         Analysis in Progress
                      </button>
                   </div>
                   <Sidebar />
                </div>
            </div>
        </div>
    </div>
  );
};

export default ArticleDetail;

import React, { useState, useEffect } from 'react';
import { Mail, Facebook, Twitter, Linkedin, Youtube, ArrowRight, Check, Instagram, Loader2, Image as ImageIcon } from 'lucide-react';
import ArticleCard from './ArticleCard';
import { AdminService, AdConfig } from '../services/adminService';
import { NewsService } from '../services/newsService';
import { Article } from '../types';

const Sidebar: React.FC = () => {
  const [email, setEmail] = useState('');
  const [subscribed, setSubscribed] = useState(false);
  const [adConfig, setAdConfig] = useState<AdConfig | null>(null);
  const [loadingAd, setLoadingAd] = useState(true);
  const [trendingArticles, setTrendingArticles] = useState<Article[]>([]);
  const [loadingTrending, setLoadingTrending] = useState(true);

  useEffect(() => {
    const loadContent = async () => {
      // 1. Load Ads
      const config = await AdminService.getAdConfig();
      setAdConfig(config);
      setLoadingAd(false);

      if (config.sidebarAd.enabled && config.sidebarAd.imageUrl) {
        AdminService.recordAdImpression('sidebarAd');
      }

      // 2. Load Real Trending Articles
      const news = await NewsService.getLatestNews('General');
      setTrendingArticles(news.slice(0, 4));
      setLoadingTrending(false);
    };
    loadContent();
  }, []);

  const handleSubscribe = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      AdminService.addSubscriber(email);
      setSubscribed(true);
      setEmail('');
      setTimeout(() => setSubscribed(false), 3000);
    }
  };

  const handleAdClick = () => {
    AdminService.recordAdClick('sidebarAd');
  };

  return (
    <aside className="space-y-8 sticky top-24">

      {/* Newsletter */}
      <div className="bg-gradient-to-br from-kph-charcoal to-gray-800 p-8 rounded-2xl shadow-lg text-white relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 group-hover:scale-150 transition-transform duration-700"></div>

        <div className="relative z-10">
            <div className="flex items-center space-x-3 mb-4 text-kph-red">
                <div className="bg-white/10 p-2 rounded-lg">
                    <Mail size={24} className="text-white" />
                </div>
                <h3 className="font-bold text-xl text-white">Newsletter</h3>
            </div>
            <p className="text-sm text-gray-300 mb-6 leading-relaxed">Join 10,000+ subscribers getting the latest political news delivered to their inbox.</p>

            {subscribed ? (
               <div className="bg-green-500/20 border border-green-500/30 rounded-lg p-3 flex items-center gap-2 text-green-300 text-sm font-bold animate-slide-up">
                  <Check size={16} /> Subscribed successfully!
               </div>
            ) : (
               <form className="space-y-3" onSubmit={handleSubscribe}>
                  <input 
                      type="email" 
                      value={email}
                      // Fixed property access from e.form.value to e.target.value
                      onChange={(e) => setEmail(e.target.value)}
                      placeholder="Email address" 
                      className="w-full px-4 py-3 bg-white/10 border border-white/20 rounded-lg focus:outline-none focus:border-kph-red focus:bg-white/20 text-white placeholder-gray-400 text-sm transition-colors"
                      required
                  />
                  <button className="w-full bg-kph-red text-white font-bold py-3 rounded-lg hover:bg-white hover:text-kph-red transition-all duration-300 shadow-md transform hover:-translate-y-0.5">
                      Subscribe Now
                  </button>
               </form>
            )}
        </div>
      </div>

      {/* Popular Posts */}
      <div className="bg-white border border-gray-100 p-6 rounded-2xl shadow-sm">
        <div className="flex justify-between items-center mb-6">
           <h3 className="font-bold text-lg text-kph-charcoal border-l-4 border-kph-red pl-3 uppercase tracking-tighter">Popular Posts</h3>
        </div>
        <div className="flex flex-col space-y-2">
            {loadingTrending ? (
               <div className="py-10 flex justify-center"><Loader2 className="animate-spin text-gray-200" /></div>
            ) : (
              trendingArticles.map((article, idx) => (
                  <ArticleCard key={article.id} article={article} variant="compact" delay={idx * 100} />
              ))
            )}
            {!loadingTrending && trendingArticles.length === 0 && (
              <p className="text-[10px] text-gray-400 uppercase text-center py-4">No recent activity found</p>
            )}
        </div>
      </div>

      {/* Dynamic Ad Space */}
      <div className="w-full">
         {loadingAd ? (
            <div className="w-full h-[250px] bg-gray-50 rounded-2xl flex items-center justify-center">
               <Loader2 className="animate-spin text-gray-200" size={32} />
            </div>
         ) : adConfig?.sidebarAd?.enabled && adConfig.sidebarAd.imageUrl ? (
            <a 
              href={adConfig.sidebarAd.linkUrl} 
              target="_blank" 
              rel="noopener noreferrer" 
              onClick={handleAdClick}
              className="block relative group overflow-hidden rounded-2xl shadow-sm border border-gray-100 transition-all hover:shadow-lg"
            >
               <img 
                 src={adConfig.sidebarAd.imageUrl} 
                 alt={adConfig.sidebarAd.altText} 
                 className="w-full h-auto object-cover group-hover:scale-105 transition-transform duration-700" 
               />
               <div className="absolute top-3 right-3 bg-white/80 backdrop-blur-md px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-tighter text-gray-600 shadow-sm">Sponsored</div>
            </a>
         ) : (
            <div className="bg-gray-100 h-[250px] w-full flex flex-col items-center justify-center rounded-2xl text-gray-400 font-bold tracking-widest border-2 border-dashed border-gray-300 relative overflow-hidden group">
               <span>ADVERTISEMENT</span>
            </div>
         )}
      </div>

    </aside>
  );
};

export default Sidebar;
